11	/// Тип радиации
12	enum RadiationType: Equatable, Codable, Hashable, Identifiable {
13	    
14	    var id: Self {
15	        self
16	    }
17	    
18	    enum Level: String, Equatable, Codable {
19	        case countRate
20	        case doseRate
21	        
22	        var accentColor: Color {
23	            switch self {
24	            case .countRate:
25	                .accentGreen
26	            case .doseRate:
27	                .accentBlue
28	            }
29	        }
30	        
31	        var title: LocalizedStringResource {
32	            switch self {
33	            case .countRate:
34	                .Localization.countRate
35	            case .doseRate:
36	                .Localization.doseRate
37	            }
38	        }
39	    }
40	    
41	    /// Уровни радиации
42	    case radiationLevel(Level)
43	    /// Доза
44	    case dose
45	    
46	    var title: LocalizedStringResource {
47	        switch self {
48	        case .radiationLevel(let level):
49	            level.title
50	        case .dose:
51	            .Localization.dose
52	        }
53	    }
54	}
55	
56	// MARK: - Сustom Decodable
57	extension RadiationType {
58	
59	    private enum RadiationKey: String, CodingKey {
60	        case radiationLevel
61	        case dose
62	    }
63	    
64	    init(from decoder: Decoder) throws {
65	        let container = try decoder.container(keyedBy: RadiationKey.self)
66	
67	        if container.contains(.dose) {
68	            self = .dose
69	            return
70	        }
71	
72	        if container.contains(.radiationLevel) {
73	            if let level = try? container.decode([String: String].self, forKey: .radiationLevel) {
74	                for value in level.values {
75	                    if let level = RadiationType.Level(rawValue: value) {
76	                        self = .radiationLevel(level)
77	                        return
78	                    }
79	                }
80	            }
81	        }
82	
83	        // Это жуткий костыль, чтобы убрать падения, при извлечении данных в SwiftData throw приводит к падению
84	        self = .radiationLevel(.countRate)
85	    }
86	}
